export enum UserStatus {
  NEW = 'NEW',
  PAYMENT_PENDING = 'PAYMENT_PENDING',
  WAITING_APPROVAL = 'WAITING_APPROVAL',
  APPROVED = 'APPROVED',
  REGISTERED = 'REGISTERED'
}

export enum ShirtSize {
  XS = 'XS',
  S = 'S',
  M = 'M',
  L = 'L',
  XL = 'XL',
  XXL = 'XXL'
}

export interface MemberData {
  whatsapp: string;
  status: UserStatus;
  paymentAmount: number; // 200000 + random digits
  paymentCode: number;   // The random digits
  fullName?: string;
  nickname?: string;
  birthYear?: number;
  birthDate?: string;
  addressKK?: string;
  addressDomicile?: string;
  shirtSize?: ShirtSize;
}

export const BIRTH_YEARS = [2024, 2023, 2022, 2021, 2020, 2019, 2018, 2017];

import { MemberData, UserStatus } from '../types';

const STORAGE_KEY = 'pushbike_kudus_db';

// Simulate network delay
const delay = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

// Helper to get DB
const getDB = (): Record<string, MemberData> => {
  const data = localStorage.getItem(STORAGE_KEY);
  return data ? JSON.parse(data) : {};
};

// Helper to save DB
const saveDB = (db: Record<string, MemberData>) => {
  localStorage.setItem(STORAGE_KEY, JSON.stringify(db));
};

export const checkMemberStatus = async (whatsapp: string): Promise<MemberData> => {
  await delay(600); // Simulate API call
  const db = getDB();

  if (db[whatsapp]) {
    return db[whatsapp];
  }

  // Create new if not exists
  const randomDigits = Math.floor(Math.random() * 90 + 10); // 10-99
  const newMember: MemberData = {
    whatsapp,
    status: UserStatus.NEW,
    paymentCode: randomDigits,
    paymentAmount: 200000 + randomDigits
  };

  db[whatsapp] = newMember;
  saveDB(db);
  return newMember;
};

export const confirmPayment = async (whatsapp: string): Promise<MemberData> => {
  await delay(800);
  const db = getDB();
  if (db[whatsapp]) {
    db[whatsapp].status = UserStatus.WAITING_APPROVAL;
    saveDB(db);
    return db[whatsapp];
  }
  throw new Error("Member not found");
};

// This function simulates the Admin approving the payment manually on the sheet
export const adminApproveMember = async (whatsapp: string): Promise<MemberData> => {
  await delay(400);
  const db = getDB();
  if (db[whatsapp]) {
    db[whatsapp].status = UserStatus.APPROVED;
    saveDB(db);
    return db[whatsapp];
  }
  throw new Error("Member not found");
};

export const submitRegistration = async (whatsapp: string, data: Partial<MemberData>): Promise<MemberData> => {
  await delay(1000);
  const db = getDB();
  if (db[whatsapp]) {
    db[whatsapp] = {
      ...db[whatsapp],
      ...data,
      status: UserStatus.REGISTERED
    };
    saveDB(db);
    return db[whatsapp];
  }
  throw new Error("Member not found");
};

import { GoogleGenAI } from "@google/genai";

// NOTE: In a real production app, ensure API keys are secured or proxied.
const API_KEY = process.env.API_KEY || ''; 

let ai: GoogleGenAI | null = null;

try {
  if (API_KEY) {
    ai = new GoogleGenAI({ apiKey: API_KEY });
  }
} catch (error) {
  console.error("Failed to initialize Gemini Client", error);
}

export const askGeminiAssistant = async (question: string): Promise<string> => {
  if (!ai) return "Maaf, asisten AI sedang tidak aktif (API Key missing).";

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: question,
      config: {
        systemInstruction: `Anda adalah asisten virtual ramah untuk 'Pushbike Kudus'. 
        Tugas anda membantu orang tua mendaftarkan anak mereka.

        Informasi penting:
        - Biaya registrasi: Rp 200.000 + kode unik (2 digit).
        - Tahun kelahiran yang diterima: 2017 sampai 2024.
        - Ukuran baju tersedia: XS, S, M, L, XL, XXL.
        - Alamat domisili bisa disamakan dengan KK.
        - Setelah transfer, tidak perlu upload bukti, cukup klik konfirmasi.
        - Tunggu admin approve baru bisa isi formulir.

        Jawablah dengan singkat, sopan, dan menyemangati. Gunakan Bahasa Indonesia.`,
      },
    });
    return response.text || "Maaf, saya tidak mengerti.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Maaf, terjadi kesalahan pada sistem AI.";
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { askGeminiAssistant } from '../services/geminiService';

const GeminiChat: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<{role: 'user' | 'bot', text: string}[]>([
    { role: 'bot', text: 'Halo! Ada yang bisa dibantu untuk pendaftaran Pushbike Kudus?' }
  ]);
  const [isLoading, setIsLoading] = useState(false);
  const endRef = useRef<HTMLDivElement>(null);

  const toggleChat = () => setIsOpen(!isOpen);

  const sendMessage = async () => {
    if (!input.trim()) return;

    const userMsg = input;
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setInput('');
    setIsLoading(true);

    const botResponse = await askGeminiAssistant(userMsg);

    setMessages(prev => [...prev, { role: 'bot', text: botResponse }]);
    setIsLoading(false);
  };

  useEffect(() => {
    endRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, isOpen]);

  return (
    <div className="fixed bottom-4 right-4 z-50 flex flex-col items-end">
      {isOpen && (
        <div className="bg-white border border-slate-200 shadow-xl rounded-lg w-80 h-96 flex flex-col mb-4 overflow-hidden">
          <div className="bg-orange-500 text-white p-3 flex justify-between items-center">
            <h3 className="font-semibold text-sm">Bantuan Pushbike</h3>
            <button onClick={toggleChat} className="text-white hover:text-orange-200">&times;</button>
          </div>
          <div className="flex-1 overflow-y-auto p-3 space-y-3 bg-slate-50">
            {messages.map((m, i) => (
              <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                <div className={`max-w-[80%] text-sm p-2 rounded-lg ${m.role === 'user' ? 'bg-orange-100 text-orange-900' : 'bg-white border text-slate-700'}`}>
                  {m.text}
                </div>
              </div>
            ))}
            {isLoading && <div className="text-xs text-slate-400 italic">Sedang mengetik...</div>}
            <div ref={endRef} />
          </div>
          <div className="p-2 bg-white border-t flex">
            <input
              type="text"
              className="flex-1 text-sm border rounded-l-md px-2 py-1 focus:outline-none focus:border-orange-500"
              placeholder="Tanya sesuatu..."
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && sendMessage()}
            />
            <button 
              onClick={sendMessage}
              disabled={isLoading}
              className="bg-orange-500 text-white px-3 py-1 rounded-r-md text-sm hover:bg-orange-600 disabled:opacity-50"
            >
              Kirim
            </button>
          </div>
        </div>
      )}
      <button 
        onClick={toggleChat}
        className="bg-orange-600 hover:bg-orange-700 text-white rounded-full p-4 shadow-lg transition-transform hover:scale-105 flex items-center justify-center"
      >
        <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
          <path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z"></path>
        </svg>
      </button>
    </div>
  );
};

