Untuk melakukan demo aplikasi ini secara mandiri (local) tanpa koneksi internet/server, Anda **tidak perlu menyiapkan apa-apa**. Kode yang saya buat saat ini menggunakan sistem **Mocking (Simulasi)**. Data disimpan sementara di memori browser (`localStorage`), sehingga Anda bisa mencoba alur login, transfer, approval admin, hingga isi formulir seolah-olah aplikasi sudah jadi.

Namun, untuk mengintegrasikannya dengan **Google Sheet yang asli (Real)** agar data benar-benar tersimpan di spreadsheet Anda, berikut langkah-langkahnya:

### 1. Siapkan Google Sheet
Buat Sheet baru di Google Drive, beri nama (misal: "Database Pushbike"), dan buat Sheet bernama `Members` dengan baris pertama (Header) sebagai berikut (urutan kolom harus sesuai):
`Whatsapp` | `Status` | `PaymentAmount` | `PaymentCode` | `FullName` | `Nickname` | `BirthYear` | `BirthDate` | `FatherName` | `MotherName` | `AddressKK` | `AddressDomicile` | `ShirtSize`

### 2. Pasang Google Apps Script (Backend)
1. Di Google Sheet, klik menu **Extensions** > **Apps Script**.
2. Hapus semua kode yang ada, copy-paste kode di bawah ini:

```javascript
// --- KODE GOOGLE APPS SCRIPT ---
var SHEET_NAME = "Members";

function doPost(e) {
  var lock = LockService.getScriptLock();
  lock.tryLock(10000);

  try {
    var sheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName(SHEET_NAME);
    if (!sheet) {
      sheet = SpreadsheetApp.getActiveSpreadsheet().insertSheet(SHEET_NAME);
      sheet.appendRow(["Whatsapp", "Status", "PaymentAmount", "PaymentCode", "FullName", "Nickname", "BirthYear", "BirthDate", "FatherName", "MotherName", "AddressKK", "AddressDomicile", "ShirtSize"]);
    }

    var data = JSON.parse(e.postData.contents);
    var action = data.action;
    var result = {};

    var rows = sheet.getDataRange().getValues();
    var headers = rows[0];
    var rowIndex = -1;

    // Cari baris berdasarkan WhatsApp (kecuali action 'get_all')
    if (data.whatsapp) {
      for (var i = 1; i < rows.length; i++) {
        if (String(rows[i][0]) == String(data.whatsapp)) {
          rowIndex = i + 1; // +1 karena index sheet mulai dari 1
          break;
        }
      }
    }

    if (action === "check_status") {
      if (rowIndex === -1) {
        // Buat member baru
        var randomCode = Math.floor(Math.random() * 90 + 10);
        var amount = 200000 + randomCode;
        sheet.appendRow([data.whatsapp, "NEW", amount, randomCode, "", "", "", "", "", "", "", "", ""]);
        result = { whatsapp: data.whatsapp, status: "NEW", paymentAmount: amount, paymentCode: randomCode };
      } else {
        // Return data yang ada
        var r = rows[rowIndex - 1];
        result = rowToData(r);
      }
    } 
    else if (action === "confirm_payment") {
      if (rowIndex > -1) {
        sheet.getRange(rowIndex, 2).setValue("WAITING_APPROVAL");
        var r = sheet.getRange(rowIndex, 1, 1, sheet.getLastColumn()).getValues()[0];
        result = rowToData(r);
      }
    }
    else if (action === "admin_approve") {
      if (rowIndex > -1) {
        sheet.getRange(rowIndex, 2).setValue("APPROVED");
        result = { success: true };
      }
    }
    else if (action === "submit_registration") {
      if (rowIndex > -1) {
        // Update kolom E (5) sampai M (13)
        var rowData = data.data;
        sheet.getRange(rowIndex, 2).setValue("REGISTERED");
        sheet.getRange(rowIndex, 5).setValue(rowData.fullName || "");
        sheet.getRange(rowIndex, 6).setValue(rowData.nickname || "");
        sheet.getRange(rowIndex, 7).setValue(rowData.birthYear || "");
        sheet.getRange(rowIndex, 8).setValue(rowData.birthDate || "");
        sheet.getRange(rowIndex, 9).setValue(rowData.fatherName || "");
        sheet.getRange(rowIndex, 10).setValue(rowData.motherName || "");
        sheet.getRange(rowIndex, 11).setValue(rowData.addressKK || "");
        sheet.getRange(rowIndex, 12).setValue(rowData.addressDomicile || "");
        sheet.getRange(rowIndex, 13).setValue(rowData.shirtSize || "");

        var r = sheet.getRange(rowIndex, 1, 1, sheet.getLastColumn()).getValues()[0];
        result = rowToData(r);
      }
    }
    else if (action === "get_all") {
      var allMembers = [];
      for (var i = 1; i < rows.length; i++) {
        allMembers.push(rowToData(rows[i]));
      }
      result = allMembers;
    }

    return ContentService.createTextOutput(JSON.stringify(result))
      .setMimeType(ContentService.MimeType.JSON);

  } catch (e) {
    return ContentService.createTextOutput(JSON.stringify({ "error": e.toString() }))
      .setMimeType(ContentService.MimeType.JSON);
  } finally {
    lock.releaseLock();
  }
}

function rowToData(row) {
  return {
    whatsapp: row[0],
    status: row[1],
    paymentAmount: row[2],
    paymentCode: row[3],
    fullName: row[4],
    nickname: row[5],
    birthYear: row[6],
    birthDate: row[7],
    fatherName: row[8],
    motherName: row[9],
    addressKK: row[10],
    addressDomicile: row[11],
    shirtSize: row[12]
  };
}
```

3. Klik tombol **Deploy** (kanan atas) > **New Deployment**.
4. Pilih type: **Web App**.
5. Description: "Versi 1".
6. Execute as: **Me**.
7. Who has access: **Anyone** (Ini penting agar aplikasi web bisa mengakses tanpa login Google).
8. Klik **Deploy**, lalu **Salin URL** yang muncul (diakhiri `/exec`).

### 3. Update Kode Aplikasi (Frontend)
Saya akan memperbarui file `services/sheetService.ts`.

Secara default, aplikasi akan tetap menggunakan mode **DEMO (Offline)** agar Anda bisa langsung mencobanya. Namun, saya telah menambahkan variabel `GOOGLE_SCRIPT_URL` di bagian atas file.

**Cara Mengaktifkan:**
Buka `services/sheetService.ts`, lalu isi variabel `GOOGLE_SCRIPT_URL` dengan URL yang Anda salin dari langkah deploy di atas. Selama variabel itu kosong `''`, aplikasi akan berjalan dalam mode demo.

Berikut perubahannya:

diffs.replacement:
import { MemberData, UserStatus } from '../types';

// ============================================================================
// CONFIGURATION
// ============================================================================
// Instruction: To use Real Google Sheets, deploy the Google Apps Script provided
// in the chat/instructions, and paste the Web App URL inside the quotes below.
// Example: "https://script.google.com/macros/s/AKfycbx.../exec"
// Leave empty "" to use the DEMO/MOCK mode (runs locally in browser).
const GOOGLE_SCRIPT_URL = ""; 
// ============================================================================

const STORAGE_KEY = 'pushbike_kudus_db';

// Simulate network delay for mock mode
const delay = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

// --- MOCK DATABASE HELPERS (LOCAL STORAGE) ---
const getDB = (): Record<string, MemberData> => {
  const data = localStorage.getItem(STORAGE_KEY);
  return data ? JSON.parse(data) : {};
};

const saveDB = (db: Record<string, MemberData>) => {
  localStorage.setItem(STORAGE_KEY, JSON.stringify(db));
};

// --- API HELPER FOR GOOGLE SHEETS ---
const callScript = async (action: string, payload: any = {}) => {
  if (!GOOGLE_SCRIPT_URL) throw new Error("Script URL not configured");

  // We use 'no-cors' workaround for some simple cases, but for data retrieval 
  // standard CORS is needed. Apps Script 'Anyone' access usually handles CORS 
  // correctly for POST if we use text/plain to avoid preflight complex checks.
  const response = await fetch(GOOGLE_SCRIPT_URL, {
    method: "POST",
    // rigid formatting to ensure GAS receives it correctly without CORS preflight block
    body: JSON.stringify({ action, ...payload })
  });

  const json = await response.json();
  if (json.error) throw new Error(json.error);
  return json;
};

// ============================================================================
// SERVICE METHODS
// ============================================================================

export const checkMemberStatus = async (whatsapp: string): Promise<MemberData> => {
  // 1. REAL MODE
  if (GOOGLE_SCRIPT_URL) {
    return await callScript('check_status', { whatsapp });
  }

  // 2. MOCK MODE
  await delay(600);
  const db = getDB();

  if (db[whatsapp]) {
    return db[whatsapp];
  }

  const randomDigits = Math.floor(Math.random() * 90 + 10); // 10-99
  const newMember: MemberData = {
    whatsapp,
    status: UserStatus.NEW,
    paymentCode: randomDigits,
    paymentAmount: 200000 + randomDigits
  };

  db[whatsapp] = newMember;
  saveDB(db);
  return newMember;
};

export const confirmPayment = async (whatsapp: string): Promise<MemberData> => {
  // 1. REAL MODE
  if (GOOGLE_SCRIPT_URL) {
    return await callScript('confirm_payment', { whatsapp });
  }

  // 2. MOCK MODE
  await delay(800);
  const db = getDB();
  if (db[whatsapp]) {
    db[whatsapp].status = UserStatus.WAITING_APPROVAL;
    saveDB(db);
    return db[whatsapp];
  }
  throw new Error("Member not found");
};

export const adminApproveMember = async (whatsapp: string): Promise<MemberData> => {
  // 1. REAL MODE
  if (GOOGLE_SCRIPT_URL) {
    await callScript('admin_approve', { whatsapp });
    // Fetch updated data to return consistent object
    return { ...(await checkMemberStatus(whatsapp)), status: UserStatus.APPROVED };
  }

  // 2. MOCK MODE
  await delay(400);
  const db = getDB();
  if (db[whatsapp]) {
    db[whatsapp].status = UserStatus.APPROVED;
    saveDB(db);
    return db[whatsapp];
  }
  throw new Error("Member not found");
};

export const submitRegistration = async (whatsapp: string, data: Partial<MemberData>): Promise<MemberData> => {
  // 1. REAL MODE
  if (GOOGLE_SCRIPT_URL) {
    return await callScript('submit_registration', { whatsapp, data });
  }

  // 2. MOCK MODE
  await delay(1000);
  const db = getDB();
  if (db[whatsapp]) {
    db[whatsapp] = {
      ...db[whatsapp],
      ...data,
      status: UserStatus.REGISTERED
    };
    saveDB(db);
    return db[whatsapp];
  }
  throw new Error("Member not found");
};

export const getAllMembers = async (): Promise<MemberData[]> => {
  // 1. REAL MODE
  if (GOOGLE_SCRIPT_URL) {
    return await callScript('get_all');
  }

  // 2. MOCK MODE
  await delay(500);
  const db = getDB();
  return Object.values(db);
};

