Struktur kolom di Google Sheet nanti akan otomatis menjadi seperti ini:
`Nomor WhatsApp` | `Status` | `Total Tagihan` | `Kode Unik` | `Nama Lengkap Anak` | `Nama Panggilan` | ... dst

### Langkah Integrasi:

1.  Buka **Google Spreadsheet** baru di Google Drive Anda.
2.  Pergi ke menu **Extensions (Ekstensi)** > **Apps Script**.
3.  Hapus semua kode yang ada, lalu **Copy & Paste** kode di bawah ini.
4.  Klik **Deploy** > **New Deployment** > Pilih **Web App**.
5.  Set **Who has access** menjadi **Anyone** (Siapa saja).
6.  Klik **Deploy** dan salin **Web App URL** yang muncul.
7.  Tempel URL tersebut ke dalam file `services/sheetService.ts` di variabel `GOOGLE_SCRIPT_URL`.

### Kode Google Apps Script (Versi Indonesia)

```javascript
var NAMA_SHEET = "Data Member Pushbike";

function doPost(e) {
  var lock = LockService.getScriptLock();
  lock.tryLock(10000);

  try {
    var ss = SpreadsheetApp.getActiveSpreadsheet();
    var sheet = ss.getSheetByName(NAMA_SHEET);

    // Jika sheet belum ada, buat otomatis dengan Header Bahasa Indonesia
    if (!sheet) {
      sheet = ss.insertSheet(NAMA_SHEET);
      // Baris 1: Header (Judul Kolom)
      sheet.appendRow([
        "Nomor WhatsApp",    // Kolom A
        "Status",            // Kolom B
        "Total Tagihan",     // Kolom C
        "Kode Unik",         // Kolom D
        "Nama Lengkap Anak", // Kolom E
        "Nama Panggilan",    // Kolom F
        "Tahun Lahir",       // Kolom G
        "Tanggal Lahir",     // Kolom H
        "Nama Ayah",         // Kolom I
        "Nama Ibu",          // Kolom J
        "Alamat KK",         // Kolom K
        "Alamat Domisili",   // Kolom L
        "Ukuran Baju"        // Kolom M
      ]);

      // Formatting Visual (Agar rapi)
      sheet.getRange("1:1").setFontWeight("bold"); // Header tebal
      sheet.getRange("C:C").setNumberFormat("Rp #,##0"); // Format Rupiah
      sheet.setFrozenRows(1); // Bekukan baris 1
    }

    // Parsing data dari Aplikasi Web
    var data = JSON.parse(e.postData.contents);
    var action = data.action;
    var result = {};

    var rows = sheet.getDataRange().getValues();
    var rowIndex = -1;

    // Mencari baris berdasarkan Nomor WhatsApp (Kolom A)
    if (data.whatsapp) {
      for (var i = 1; i < rows.length; i++) {
        // String comparison untuk keamanan
        if (String(rows[i][0]) == String(data.whatsapp)) {
          rowIndex = i + 1; // +1 karena array mulai dari 0 tapi sheet mulai dari 1
          break;
        }
      }
    }

    // --- ALUR PROSES ---

    // 1. Cek Status Login / Member Baru
    if (action === "check_status") {
      if (rowIndex === -1) {
        // Buat Member Baru
        var randomCode = Math.floor(Math.random() * 90 + 10);
        var amount = 200000 + randomCode;

        sheet.appendRow([
          data.whatsapp, 
          "NEW", 
          amount, 
          randomCode, 
          "", "", "", "", "", "", "", "", ""
        ]);

        // Kembalikan data ke aplikasi
        result = { 
          whatsapp: data.whatsapp, 
          status: "NEW", 
          paymentAmount: amount, 
          paymentCode: randomCode 
        };
      } else {
        // Member Sudah Ada, kembalikan data lama
        result = barisKeData(rows[rowIndex - 1]);
      }
    } 

    // 2. Member Konfirmasi Transfer
    else if (action === "confirm_payment") {
      if (rowIndex > -1) {
        sheet.getRange(rowIndex, 2).setValue("WAITING_APPROVAL");
        result = barisKeData(sheet.getRange(rowIndex, 1, 1, 13).getValues()[0]);
      }
    }

    // 3. Admin Menyetujui (Approval)
    else if (action === "admin_approve") {
      if (rowIndex > -1) {
        sheet.getRange(rowIndex, 2).setValue("APPROVED");
        result = { success: true };
      }
    }

    // 4. Submit Formulir Data Diri
    else if (action === "submit_registration") {
      if (rowIndex > -1) {
        var d = data.data;
        sheet.getRange(rowIndex, 2).setValue("REGISTERED");

        // Simpan data formulir ke kolom E - M
        sheet.getRange(rowIndex, 5).setValue(d.fullName || "");
        sheet.getRange(rowIndex, 6).setValue(d.nickname || "");
        sheet.getRange(rowIndex, 7).setValue(d.birthYear || "");
        sheet.getRange(rowIndex, 8).setValue(d.birthDate || ""); // Format YYYY-MM-DD
        sheet.getRange(rowIndex, 9).setValue(d.fatherName || "");
        sheet.getRange(rowIndex, 10).setValue(d.motherName || "");
        sheet.getRange(rowIndex, 11).setValue(d.addressKK || "");
        sheet.getRange(rowIndex, 12).setValue(d.addressDomicile || "");
        sheet.getRange(rowIndex, 13).setValue(d.shirtSize || "");

        result = barisKeData(sheet.getRange(rowIndex, 1, 1, 13).getValues()[0]);
      }
    }

    // 5. Ambil Semua Data (Untuk Dashboard Admin)
    else if (action === "get_all") {
      var allData = [];
      for (var i = 1; i < rows.length; i++) {
        allData.push(barisKeData(rows[i]));
      }
      result = allData;
    }

    return ContentService.createTextOutput(JSON.stringify(result))
      .setMimeType(ContentService.MimeType.JSON);

  } catch (err) {
    return ContentService.createTextOutput(JSON.stringify({ "error": err.toString() }))
      .setMimeType(ContentService.MimeType.JSON);
  } finally {
    lock.releaseLock();
  }
}

// Fungsi Helper: Mapping Kolom Sheet (Indo) -> Object JSON (Aplikasi)
// Ini penting agar aplikasi React tetap bisa membaca data meski kolomnya Bahasa Indonesia
function barisKeData(row) {
  return {
    whatsapp: row[0],      // Kolom A
    status: row[1],        // Kolom B
    paymentAmount: row[2], // Kolom C
    paymentCode: row[3],   // Kolom D
    fullName: row[4],      // Kolom E
    nickname: row[5],      // Kolom F
    birthYear: row[6],     // Kolom G
    birthDate: row[7],     // Kolom H
    fatherName: row[8],    // Kolom I
    motherName: row[9],    // Kolom J
    addressKK: row[10],    // Kolom K
    addressDomicile: row[11], // Kolom L
    shirtSize: row[12]     // Kolom M
  };
}
```

Setelah Anda mendeploy skrip ini dan mendapatkan URL-nya, jangan lupa masukkan URL tersebut ke dalam file `services/sheetService.ts` di aplikasi Anda agar mode **Mock (Demo)** berubah menjadi mode **Live (Google Sheet)**.

