### 2. Update Kode Google Apps Script (Wajib Di-update)

Agar fitur **Wipe Data / Hapus Semua** bekerja di Google Sheet, Anda **HARUS meng-update kode Google Apps Script** Anda dengan versi di bawah ini. Versi ini menambahkan logika untuk `wipe_all`.

**Langkah:**
1. Buka Google Spreadsheet > Extensions > Apps Script.
2. Hapus semua kode lama, ganti dengan yang di bawah ini.
3. Klik **Deploy** > **Manage Deployments**.
4. Klik icon pensil (Edit) pada deployment yang aktif.
5. Pada dropdown version, pilih **New version**.
6. Klik **Deploy**. (URL tidak akan berubah, jadi tidak perlu update URL di aplikasi).

```javascript
var NAMA_SHEET = "Data Member Pushbike";

function doPost(e) {
  var lock = LockService.getScriptLock();
  lock.tryLock(10000);

  try {
    var ss = SpreadsheetApp.getActiveSpreadsheet();
    var sheet = ss.getSheetByName(NAMA_SHEET);

    // Inisialisasi Sheet jika belum ada
    if (!sheet) {
      sheet = ss.insertSheet(NAMA_SHEET);
      setupHeader(sheet);
    }

    var data = JSON.parse(e.postData.contents);
    var action = data.action;
    var result = {};

    // Khusus untuk action Wipe All, kita tidak perlu cari baris
    if (action === "wipe_all") {
      // Hapus sheet dan buat baru agar bersih total
      ss.deleteSheet(sheet);
      sheet = ss.insertSheet(NAMA_SHEET);
      setupHeader(sheet);
      return createJSONOutput({ success: true, message: "Database wiped." });
    }

    var rows = sheet.getDataRange().getValues();
    var rowIndex = -1;

    // Cari baris member
    if (data.whatsapp) {
      for (var i = 1; i < rows.length; i++) {
        if (String(rows[i][0]) == String(data.whatsapp)) {
          rowIndex = i + 1;
          break;
        }
      }
    }

    // --- LOGIKA UTAMA ---

    if (action === "check_status") {
      if (rowIndex === -1) {
        var randomCode = Math.floor(Math.random() * 90 + 10);
        var amount = 200000 + randomCode;
        sheet.appendRow([data.whatsapp, "NEW", amount, randomCode, "", "", "", "", "", "", "", "", ""]);
        result = { whatsapp: data.whatsapp, status: "NEW", paymentAmount: amount, paymentCode: randomCode };
      } else {
        result = barisKeData(rows[rowIndex - 1]);
      }
    } 
    else if (action === "confirm_payment") {
      if (rowIndex > -1) {
        sheet.getRange(rowIndex, 2).setValue("WAITING_APPROVAL");
        result = barisKeData(sheet.getRange(rowIndex, 1, 1, 13).getValues()[0]);
      }
    }
    else if (action === "admin_approve") {
      if (rowIndex > -1) {
        sheet.getRange(rowIndex, 2).setValue("APPROVED");
        result = { success: true };
      }
    }
    else if (action === "submit_registration") {
      if (rowIndex > -1) {
        var d = data.data;
        sheet.getRange(rowIndex, 2).setValue("REGISTERED");
        sheet.getRange(rowIndex, 5).setValue(d.fullName || "");
        sheet.getRange(rowIndex, 6).setValue(d.nickname || "");
        sheet.getRange(rowIndex, 7).setValue(d.birthYear || "");
        sheet.getRange(rowIndex, 8).setValue(d.birthDate || "");
        sheet.getRange(rowIndex, 9).setValue(d.fatherName || "");
        sheet.getRange(rowIndex, 10).setValue(d.motherName || "");
        sheet.getRange(rowIndex, 11).setValue(d.addressKK || "");
        sheet.getRange(rowIndex, 12).setValue(d.addressDomicile || "");
        sheet.getRange(rowIndex, 13).setValue(d.shirtSize || "");
        result = barisKeData(sheet.getRange(rowIndex, 1, 1, 13).getValues()[0]);
      }
    }
    else if (action === "get_all") {
      var allData = [];
      for (var i = 1; i < rows.length; i++) {
        allData.push(barisKeData(rows[i]));
      }
      result = allData;
    }

    return createJSONOutput(result);

  } catch (err) {
    return createJSONOutput({ "error": err.toString() });
  } finally {
    lock.releaseLock();
  }
}

function setupHeader(sheet) {
  sheet.appendRow([
    "Nomor WhatsApp", "Status", "Total Tagihan", "Kode Unik", 
    "Nama Lengkap Anak", "Nama Panggilan", "Tahun Lahir", "Tanggal Lahir", 
    "Nama Ayah", "Nama Ibu", "Alamat KK", "Alamat Domisili", "Ukuran Baju"
  ]);
  sheet.getRange("1:1").setFontWeight("bold");
  sheet.getRange("C:C").setNumberFormat("Rp #,##0");
  sheet.setFrozenRows(1);
}

function createJSONOutput(data) {
  return ContentService.createTextOutput(JSON.stringify(data)).setMimeType(ContentService.MimeType.JSON);
}

function barisKeData(row) {
  return {
    whatsapp: row[0], status: row[1], paymentAmount: row[2], paymentCode: row[3],
    fullName: row[4], nickname: row[5], birthYear: row[6], birthDate: row[7],
    fatherName: row[8], motherName: row[9], addressKK: row[10], addressDomicile: row[11], shirtSize: row[12]
  };
}

