export default function App() {
  const [viewMode, setViewMode] = useState<'user' | 'admin'>('user');
  const [member, setMember] = useState<MemberData | null>(null);
  const [showAdminLogin, setShowAdminLogin] = useState(false);

  // Auto-config logic: Check URL for ?config=SCRIPT_URL
  useEffect(() => {
    const params = new URLSearchParams(window.location.search);
    const configParam = params.get('config');
    if (configParam) {
      try {
        const decodedUrl = decodeURIComponent(configParam);
        SheetService.setScriptUrl(decodedUrl);
        // Remove param from URL for cleaner UI (optional)
        const cleanUrl = window.location.protocol + "//" + window.location.host + window.location.pathname;
        window.history.replaceState({path: cleanUrl}, '', cleanUrl);
        // Note: AdminDashboard inside will read the updated localStorage on mount/interaction
      } catch (e) {
        console.error("Failed to parse config url", e);
      }
    }
  }, []);

  const handleLogin = async (wa: string) => {
    try {
      const data = await SheetService.checkMemberStatus(wa);
      setMember(data);
    } catch (error) {
      console.error(error);
      // Don't alert on background polling unless it's a hard failure
    }
  };

  const handlePaymentConfirm = async (method: PaymentMethod) => {
    if (!member) return;
    try {
      const updated = await SheetService.confirmPayment(member.whatsapp, method);
      setMember(updated);
    } catch (error) {
      console.error(error);
      alert("Gagal melakukan konfirmasi. Silakan coba lagi.");
    }
  };

  const handleSubmitForm = async (data: Partial<MemberData>) => {
    if (!member) return;
    try {
      const updated = await SheetService.submitRegistration(member.whatsapp, data);
      setMember(updated);
    } catch (error) {
      console.error(error);
      alert("Gagal menyimpan data. Silakan coba lagi.");
    }
  };

  const handleChangeView = (view: 'user' | 'admin') => {
    if (view === 'admin') {
      setShowAdminLogin(true);
    } else {
      setViewMode('user');
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 font-sans pb-20">
      <Header currentView={viewMode} onViewChange={handleChangeView} />

      {/* Admin Login Modal */}
      <AdminLoginModal 
        isOpen={showAdminLogin} 
        onClose={() => setShowAdminLogin(false)} 
        onSuccess={() => {
          setViewMode('admin');
          setShowAdminLogin(false);
        }}
      />

      <main className="max-w-md mx-auto p-4 mt-6">
        {viewMode === 'admin' ? (
          <div className="bg-white rounded-2xl shadow-sm border border-slate-100">
            <AdminDashboard />
          </div>
        ) : (
          <div className="bg-white rounded-2xl shadow-sm border border-slate-100 p-6">
            {!member && (
              <StepLogin onLogin={handleLogin} />
            )}

            {member && member.status === UserStatus.NEW && (
              <StepPayment member={member} onConfirm={handlePaymentConfirm} />
            )}

            {member && member.status === UserStatus.WAITING_APPROVAL && (
               <div className="relative">
                  <StepWaitingApproval onCheckStatus={() => handleLogin(member.whatsapp)} />
               </div>
            )}

            {member && member.status === UserStatus.APPROVED && (
              <StepForm onSubmit={handleSubmitForm} />
            )}

            {member && member.status === UserStatus.REGISTERED && (
              <StepSuccess />
            )}
          </div>
        )}
      </main>

      {viewMode === 'user' && <GeminiChat />}
    </div>
  );
}

import { MemberData, UserStatus, PaymentMethod } from '../types';

const STORAGE_KEY = 'pushbike_kudus_db';
const SCRIPT_URL_KEY = 'pushbike_script_url';

// Simulate network delay for mock mode
const delay = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

// --- CONFIGURATION HELPERS ---

export const setScriptUrl = (url: string) => {
  if (url && url.trim().length > 0) {
    localStorage.setItem(SCRIPT_URL_KEY, url.trim());
  } else {
    localStorage.removeItem(SCRIPT_URL_KEY);
  }
};

export const getScriptUrl = (): string => {
  return localStorage.getItem(SCRIPT_URL_KEY) || "";
};

const getActiveUrl = (): string => {
  return getScriptUrl();
};

// --- MOCK DATABASE HELPERS (LOCAL STORAGE) ---
const getDB = (): Record<string, MemberData> => {
  const data = localStorage.getItem(STORAGE_KEY);
  return data ? JSON.parse(data) : {};
};

const saveDB = (db: Record<string, MemberData>) => {
  localStorage.setItem(STORAGE_KEY, JSON.stringify(db));
};

// --- API HELPER FOR GOOGLE SHEETS ---
const callScript = async (action: string, payload: any = {}) => {
  const url = getActiveUrl();
  if (!url) throw new Error("Script URL not configured");

  // We use standard fetch. Apps Script 'Anyone' access handles CORS for POST requests.
  // Note: ensure the GAS deployment is set to 'Anyone' access.
  const response = await fetch(url, {
    method: "POST",
    body: JSON.stringify({ action, ...payload })
  });

  const json = await response.json();
  if (json.error) throw new Error(json.error);
  return json;
};

// ============================================================================
// SERVICE METHODS
// ============================================================================

export const checkMemberStatus = async (whatsapp: string, nickname?: string): Promise<MemberData> => {
  // 1. REAL MODE
  if (getActiveUrl()) {
    try {
      return await callScript('check_status', { whatsapp, nickname });
    } catch (e) {
      console.warn("API Error, falling back to mock check for safety", e);
      throw e;
    }
  }

  // 2. MOCK MODE
  await delay(600);
  const db = getDB();

  if (db[whatsapp]) {
    return db[whatsapp];
  }

  const randomDigits = Math.floor(Math.random() * 90 + 10); // 10-99
  const newMember: MemberData = {
    whatsapp,
    nickname: nickname || '',
    status: UserStatus.NEW,
    paymentCode: randomDigits,
    paymentAmount: 200000 + randomDigits // Default to transfer amount initially
  };

  db[whatsapp] = newMember;
  saveDB(db);
  return newMember;
};

export const confirmPayment = async (whatsapp: string, method: PaymentMethod): Promise<MemberData> => {
  // 1. REAL MODE
  if (getActiveUrl()) {
    return await callScript('confirm_payment', { whatsapp, method });
  }

  // 2. MOCK MODE
  await delay(800);
  const db = getDB();
  if (db[whatsapp]) {
    db[whatsapp].status = UserStatus.WAITING_APPROVAL;
    db[whatsapp].paymentMethod = method;

    // If Cash, normalize amount to flat 200,000. If Transfer, ensure it keeps the unique code.
    if (method === 'CASH') {
        db[whatsapp].paymentAmount = 200000;
    } else {
        // Ensure unique code exists if switching back to transfer
        if (db[whatsapp].paymentAmount === 200000) {
             const randomDigits = db[whatsapp].paymentCode || Math.floor(Math.random() * 90 + 10);
             db[whatsapp].paymentCode = randomDigits;
             db[whatsapp].paymentAmount = 200000 + randomDigits;
        }
    }

    saveDB(db);
    return db[whatsapp];
  }
  throw new Error("Member not found");
};

export const adminApproveMember = async (whatsapp: string): Promise<MemberData> => {
  // 1. REAL MODE
  if (getActiveUrl()) {
    await callScript('admin_approve', { whatsapp });
    // Fetch updated data to return consistent object
    return { ...(await checkMemberStatus(whatsapp)), status: UserStatus.APPROVED };
  }

  // 2. MOCK MODE
  await delay(400);
  const db = getDB();
  if (db[whatsapp]) {
    db[whatsapp].status = UserStatus.APPROVED;
    saveDB(db);
    return db[whatsapp];
  }
  throw new Error("Member not found");
};

export const submitRegistration = async (whatsapp: string, data: Partial<MemberData>): Promise<MemberData> => {
  // 1. REAL MODE
  if (getActiveUrl()) {
    return await callScript('submit_registration', { whatsapp, data });
  }

  // 2. MOCK MODE
  await delay(1000);
  const db = getDB();
  if (db[whatsapp]) {
    db[whatsapp] = {
      ...db[whatsapp],
      ...data,
      status: UserStatus.REGISTERED
    };
    saveDB(db);
    return db[whatsapp];
  }
  throw new Error("Member not found");
};

export const getAllMembers = async (): Promise<MemberData[]> => {
  // 1. REAL MODE
  if (getActiveUrl()) {
    return await callScript('get_all');
  }

  // 2. MOCK MODE
  await delay(500);
  const db = getDB();
  return Object.values(db);
};

export const wipeAllData = async (): Promise<void> => {
  // 1. REAL MODE
  if (getActiveUrl()) {
    await callScript('wipe_all');
    return;
  }

  // 2. MOCK MODE
  await delay(1000);
  localStorage.removeItem(STORAGE_KEY);
};

