// 3. LINK GRUP WHATSAPP (Isi link di dalam tanda kutip, kosongkan jika belum ada)
const WA_GROUP_LINK = "https://chat.whatsapp.com/L3MVbYUKRnIEyfbCQJrrwP"; // Contoh: "https://chat.whatsapp.com/ABCDE12345"

