                 </div>
              )}

              {(m.status === UserStatus.WAITING_APPROVAL || m.status === UserStatus.NEW) && (
                <div className="pt-2 border-t border-slate-100 mt-1">
                  <button 
                    onClick={() => handleApprove(m.whatsapp)}
