const App = () => {
  const [whatsapp, setWhatsapp] = useState('');
  const [member, setMember] = useState<MemberData | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const handleCheck = async () => {
    if (!whatsapp.trim()) return;
    setLoading(true);
    setError('');
    try {
      const data = await checkMemberStatus(whatsapp.trim());
      setMember(data);
    } catch (e: any) {
      setError(e.message || "Gagal memuat data");
    } finally {
      setLoading(false);
    }
  };

  const handleConfirmPayment = async (method: PaymentMethod) => {
     if (!member) return;
     setLoading(true);
     try {
        const data = await confirmPayment(member.whatsapp, method);
        setMember(data);
     } catch (e: any) {
        setError(e.message || "Gagal konfirmasi pembayaran");
     } finally {
        setLoading(false);
     }
  };

  const handleSubmitRegistration = async (data: Partial<MemberData>) => {
     if (!member) return;
     setLoading(true);
     try {
        const result = await submitRegistration(member.whatsapp, data);
        setMember(result);
     } catch (e: any) {
        setError(e.message || "Gagal simpan data");
     } finally {
        setLoading(false);
     }
  };

  const renderStep = () => {
    if (!member) {
      return (
         <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm text-center animate-fade-in">
            <h2 className="text-xl font-bold mb-4 text-slate-800">Cek Status Pendaftaran</h2>
            <input 
              type="text" 
              className="w-full border border-slate-300 p-3 rounded-lg text-lg text-center tracking-widest mb-4 focus:border-orange-500 focus:outline-none"
              placeholder="08xxxxxxxxxx"
              value={whatsapp}
              onChange={e => setWhatsapp(e.target.value)}
            />
            <button 
              onClick={handleCheck}
              disabled={loading || !whatsapp}
              className="w-full bg-orange-500 text-white font-bold py-3 rounded-xl hover:bg-orange-600 transition disabled:opacity-50"
            >
              {loading ? 'Memuat...' : 'Mulai / Cek'}
            </button>
         </div>
      );
    }

    switch (member.status) {
      case UserStatus.NEW:
        return <StepPayment member={member} onConfirm={handleConfirmPayment} />;
      case UserStatus.PAYMENT_PENDING: 
      case UserStatus.WAITING_APPROVAL:
        return (
          <div className="bg-white p-8 rounded-xl border border-slate-200 shadow-sm text-center space-y-4 animate-fade-in">
             <div className="w-20 h-20 bg-yellow-100 rounded-full flex items-center justify-center mx-auto text-yellow-600">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-10 w-10" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
             </div>
             <h2 className="text-xl font-bold text-slate-800">Menunggu Verifikasi</h2>
             <p className="text-slate-600">
                Pembayaran Anda sedang diverifikasi oleh admin. <br/>
                Mohon cek secara berkala.
             </p>
             <button onClick={handleCheck} className="text-orange-600 font-semibold hover:underline">
                Segarkan Status
             </button>
          </div>
        );
      case UserStatus.APPROVED:
        return <StepRegistration member={member} onSubmit={handleSubmitRegistration} />;
      case UserStatus.REGISTERED:
        return (
          <div className="bg-white p-8 rounded-xl border border-green-200 shadow-sm text-center space-y-4 bg-green-50 animate-fade-in">
             <div className="w-20 h-20 bg-green-100 rounded-full flex items-center justify-center mx-auto text-green-600">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-10 w-10" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" /></svg>
             </div>
             <h2 className="text-xl font-bold text-green-800">Pendaftaran Berhasil!</h2>
             <p className="text-green-700">
                Data Anda telah tersimpan. Sampai jumpa di latihan!
             </p>
             <button onClick={() => { setMember(null); setWhatsapp(''); }} className="text-slate-500 text-sm hover:underline mt-4">
                Kembali ke Awal
             </button>
          </div>
        );
      default:
        return <div className="text-center text-red-500">Status tidak valid.</div>;
    }
  };

  return (
    <div className="min-h-screen bg-slate-100 font-sans text-slate-900 pb-20">
       <div className="max-w-md mx-auto min-h-screen flex flex-col bg-slate-50 shadow-2xl">
          <div className="bg-white p-4 shadow-sm z-10 sticky top-0 flex items-center justify-center gap-3">
             <img src={getLogoUrl()} alt="Logo" className="h-10 w-10 object-contain" />
             <h1 className="font-bold text-lg text-slate-800 tracking-tight">PUSHBIKE KUDUS</h1>
          </div>

          <div className="flex-1 p-4 md:p-6 overflow-y-auto">
             {error && (
               <div className="bg-red-50 border border-red-200 text-red-600 px-4 py-3 rounded-xl text-sm mb-4 flex items-start gap-2">
                 <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 flex-shrink-0" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM8.707 7.293a1 1 0 00-1.414 1.414L8.586 10l-1.293 1.293a1 1 0 101.414 1.414L10 11.414l1.293 1.293a1 1 0 001.414-1.414L11.414 10l1.293-1.293a1 1 0 00-1.414-1.414L10 8.586 8.707 7.293z" clipRule="evenodd" /></svg>
                 <span>{error}</span>
               </div>
             )}
             {renderStep()}
          </div>
       </div>
       <GeminiChat />
    </div>
  );
}

export default App;

