                  </button>
                </div>
              )}
            </div>
          ))}
        </div>
      )}

      {/* APPEARANCE SETTINGS SECTION */}
      <div className="bg-white rounded-xl border border-slate-200 overflow-hidden mt-8 shadow-sm">
