  const [logoUrl, setLogoUrl] = useState(SheetService.getLogoUrl(DEFAULT_APP_LOGO));

  const [isEditingConfig, setIsEditingConfig] = useState(false);
  const [isEditingLogo, setIsEditingLogo] = useState(false);

