// --- COPY KODE INI KE GOOGLE APPS SCRIPT ---
// Cara: Extensions > Apps Script > Paste > Deploy as Web App (Access: Anyone)
// Versi: v7 (Fix Backward Compatibility for Old Data)

var FIELD_MAPPING = [
