  var nickname = params.nickname || "";
  var childCount = Number(params.childCount) || 1;
  var rowIndex = findRowIndex(sheet, colMap, wa);

  if (rowIndex == -1) {
    var randomCode = Math.floor(Math.random() * 90 + 10);
    var basePrice = childCount == 2 ? 300000 : 200000;
