                        </p>
                         <p className="flex justify-between">
                        <span className="text-slate-500">Size:</span>
                        <span className="font-medium text-slate-800">{m.shirtSize}</span>
                        </p>
                    </div>

                    {/* Data Anak 2 (If Exists) */}
